/* ==== list-record-paises: Mover "+ Agregar" arriba de la tabla ==== */
[selector="list-record-paises"] .data-table {
  display: flex;
  flex-direction: column;
}

/* 1) Título (si existe) se mantiene primero */
[selector="list-record-paises"] .data-table > .row.mb-2.ml-0.mr-0 {
  order: 1;
}

/* 2) El contenedor del botón "+ Agregar" antes de la tabla */
[selector="list-record-paises"] .data-table > .d-flex.justify-content-between.align-items-center {
  order: 2;
  width: 100%;
  justify-content: flex-end !important;
  margin: .25rem 0 .5rem;
}

/* Ajuste columnas internas para que no “empujen” el botón */
[selector="list-record-paises"] .data-table > .d-flex.justify-content-between.align-items-center > .col {
  flex: 0 0 auto;
  max-width: unset;
}
[selector="list-record-paises"] .data-table > .d-flex.justify-content-between.align-items-center > .col.text-left {
  display: none;
}
[selector="list-record-paises"] .data-table > .d-flex.justify-content-between.align-items-center > .col.text-right {
  display: block;
}

/* Botón “Agregar” más visible */
[selector="list-record-paises"] .data-table > .d-flex [data-cy="add-row"].btn {
  font-weight: 600;
  border-radius: 6px;
  padding: .35rem .9rem;
  box-shadow: 0 2px 8px rgba(0,0,0,.08);
  margin: 0 -10px 10px 0;
}

/* 3) La tabla queda tercera */
[selector="list-record-paises"] .data-table > table.record-list-table-secondary {
  order: 3;
}

/* (Opcional) separa visualmente el botón de la tabla en desktop */
@media (min-width: 576px) {
  [selector="list-record-paises"] .data-table > .d-flex.justify-content-between.align-items-center {
    margin-bottom: .75rem;
  }
}

/* ================================
   1) Encabezado: traducir "Actions" → "Acciones"
================================ */
[selector="list-record-paises"] table.record-list-table-secondary thead th.text-right > div {
  position: relative;
  color: transparent; /* oculta el texto original */
}
[selector="list-record-paises"] table.record-list-table-secondary thead th.text-right > div::after {
  content: "Acciones";
  position: absolute;
  right: 0; left: auto; top: 0;
  color: #2c3e50;
  font-weight: 600;
  text-align: right;
  width: 100%;
}

/* ================================
   2) Colores de íconos Editar/Eliminar
   (SVG embebidos como )
================================ */
/* EDITAR -> Azul Zurich (#0f4c81) */
[selector="list-record-paises"] td[aria-colindex="11"] .actions [title="Editar"] img{
  transition: filter .15s ease, transform .12s ease;
  filter: invert(17%) sepia(22%) saturate(2557%) hue-rotate(171deg) brightness(92%) contrast(92%);
}
[selector="list-record-paises"] td[aria-colindex="11"] .actions [title="Editar"]:hover img{
  filter: invert(13%) sepia(27%) saturate(2412%) hue-rotate(173deg) brightness(80%) contrast(95%);
  transform: translateY(-1px);
}

/* ELIMINAR -> Rojo (#dc2626) */
[selector="list-record-paises"] td[aria-colindex="11"] .actions [title="Eliminar"] img{
  transition: filter .15s ease, transform .12s ease;
  filter: invert(14%) sepia(90%) saturate(6268%) hue-rotate(356deg) brightness(90%) contrast(104%);
}
[selector="list-record-paises"] td[aria-colindex="11"] .actions [title="Eliminar"]:hover img{
  filter: invert(11%) sepia(93%) saturate(5530%) hue-rotate(355deg) brightness(70%) contrast(110%);
  transform: translateY(-1px);
}

/* Accesibilidad: micro-resalte al enfocar con teclado */
[selector="list-record-paises"] td[aria-colindex="11"] .actions .btn:focus img{
  outline: none;
  filter: drop-shadow(0 0 0.25rem rgba(15,76,129,.35));
}

/* ================================
   3) POPOVER dinámico anclado al grupo de acciones
   (reemplaza tu margin-top fijo)
================================ */

/* Asegura que el popover pueda “salirse” visualmente de la celda */
[selector="list-record-paises"] td[aria-colindex="11"]{
  overflow: visible; /* para que no lo recorte la celda */
}

/* El contenedor de botones será el ancla de posicionamiento */
[selector="list-record-paises"] td[aria-colindex="11"] .actions{
  position: relative; /* ancla */
  z-index: 1;
}

/* Popover colocado respecto a .actions, sin offsets mágicos */
[selector="list-record-paises"] td[aria-colindex="11"] .actions .popover-content{
  position: absolute;
  right: 0;
  /* —> mostrar ARRIBA de los botones (no abajo) */
  top: auto;
  bottom: calc(100% + 8px);
  z-index: 2000;

  margin-top: 0 !important;
  background: #fff;
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  padding: 10px 12px;
  box-shadow: 0 10px 24px rgba(0,0,0,.12);
  width: max-content;
  max-width: clamp(220px, 40vw, 320px);
}

/* Flechita del popover (opcional) */
[selector="list-record-paises"] td[aria-colindex="11"] .actions .popover-content::before{
  content: "";
  position: absolute;
  bottom: -6px;
  right: 14px;
  border-width: 6px;
  border-style: solid;
  border-color: #fff transparent transparent transparent;
  filter: drop-shadow(0 1px 0 #e5e7eb);
}

/* Variante para mostrarlo hacia arriba cuando no hay espacio abajo */
[selector="list-record-paises"] td[aria-colindex="11"] .actions .popover-content.popover--top{
  top: auto;
  bottom: calc(100% + 8px);
}
[selector="list-record-paises"] td[aria-colindex="11"] .actions .popover-content.popover--top::before{
  top: auto;
  bottom: -6px;
  border-color: #fff transparent transparent transparent;
  filter: drop-shadow(0 1px 0 #e5e7eb);
}

/* Limitar el alcance a tu tabla */
[selector="list-record-paises"] .actions .popover-content p,
[selector="list-record-paises"] .actions .popover-content .btn {
  position: relative;
  /* Oculta el texto original sin romper layout */
  color: transparent !important;
  font-size: 0 !important;
}

/* Texto del mensaje */
[selector="list-record-paises"] .actions .popover-content p::after {
  content: "¿Confirmas que deseas eliminar este registro?";
  font-size: 0.95rem;
  color: #111827;
  line-height: 1.35;
  display: block;
}

/* Botón CANCEL → Cancelar */
[selector="list-record-paises"] .actions .popover-content .btn.btn-light::after {
  content: "Cancelar";
  font-size: 0.875rem;
  color: #374151;
}

/* Botón DELETE → Eliminar */
[selector="list-record-paises"] .actions .popover-content .btn.btn-danger::after {
  content: "Eliminar";
  font-size: 0.875rem;
  color: #fff;
}

/* Mantener clics y foco normal (el pseudo no captura eventos) */
[selector="list-record-paises"] .actions .popover-content p::after,
[selector="list-record-paises"] .actions .popover-content .btn::after {
  pointer-events: none;
}

[selector="list-record-paises"] .data-table.max-rows [data-cy="add-row"].btn {
  display: none !important;
}
